sys_script_include.script:
var IncentNowFiscalPeriodGenerator = Class.create();
IncentNowFiscalPeriodGenerator.prototype = {

    initialize: function () {},

    generatePeriods: function (fiscalYearSysId) {


        var fy = new GlideRecordSecure('x_ctans_incentnow_fiscal_calendar');
        if (!fy.get(fiscalYearSysId)) {
            gs.error('Fiscal year not found');
            return;
        }

        var fiscalStartMonth = parseInt(fy.fiscal_start, 10);
        var fiscalEndMonth   = parseInt(fy.fiscal_end, 10);
        var fiscalStartYear  = this._extractYear(fy.fiscal_year + '');

        if (!fiscalStartMonth || !fiscalEndMonth || !fiscalStartYear) {
            gs.error('Invalid fiscal configuration');
            return;
        }

        // Prevent duplicates
        var dup = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
        dup.addQuery('fiscal_year', fy.sys_id);
        dup.setLimit(1);
        dup.query();
        if (dup.hasNext()) {
            gs.warn('Fiscal periods already exist');
            return;
        }

        /* =====================================================
         * 1 Generate YEAR Period (ROOT)
         * ===================================================== */

        var yearStart = new GlideDateTime();
        yearStart.setValue(
            fiscalStartYear + '-' + this._pad(fiscalStartMonth) + '-01 00:00:00'
        );

        var yearEnd = new GlideDateTime(yearStart);
        yearEnd.addMonthsUTC(12);
        yearEnd.addDaysUTC(-1);

        var yearRec = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
        yearRec.initialize();
        yearRec.fiscal_year = fy.sys_id;
        yearRec.period_type = 'year';
        yearRec.period_number = 1;
		yearRec.period_display_name = fy.getDisplayValue();
        yearRec.period_name = fy.fiscal_year + '';
        yearRec.period_start_date = yearStart;
        yearRec.period_end_date = yearEnd;

        var yearSysId = yearRec.insert();

        /* =====================================================
         * 2️ Generate Quarters (Children of Year)
         * ===================================================== */

        var quarters = [];

        for (var q = 0; q < 4; q++) {

            var offset = q * 3;

            var startMonth =
                ((fiscalStartMonth - 1 + offset) % 12) + 1;

            var startYear =
                fiscalStartYear +
                Math.floor((fiscalStartMonth - 1 + offset) / 12);

            var qStart = new GlideDateTime();
            qStart.setValue(
                startYear + '-' + this._pad(startMonth) + '-01 00:00:00'
            );

            var qEnd = new GlideDateTime(qStart);
            qEnd.addMonthsUTC(3);
            qEnd.addDaysUTC(-1);

            var qRec = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
            qRec.initialize();
            qRec.fiscal_year = fy.sys_id;
            qRec.period_type = 'quarter';
            qRec.period_number = q + 1;
            qRec.parent_period = yearSysId; 
            qRec.period_name = 'Q' + (q + 1) + ' ' + startYear;
			qRec.period_display_name = qRec.period_name;
            qRec.period_start_date = qStart;
            qRec.period_end_date = qEnd;

            quarters.push(qRec.insert());
        }

        /* =====================================================
         * 3️ Generate Months (Children of Quarters)
         * ===================================================== */

        for (var m = 0; m < 12; m++) {

            var month =
                ((fiscalStartMonth - 1 + m) % 12) + 1;

            var year =
                fiscalStartYear +
                Math.floor((fiscalStartMonth - 1 + m) / 12);

            var mStart = new GlideDateTime();
            mStart.setValue(
                year + '-' + this._pad(month) + '-01 00:00:00'
            );

            var mEnd = new GlideDateTime(mStart);
            mEnd.addMonthsUTC(1);
            mEnd.addDaysUTC(-1);

            var mRec = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
            mRec.initialize();
            mRec.fiscal_year = fy.sys_id;
            mRec.period_type = 'month';
            mRec.period_number = m + 1;
            mRec.parent_period = quarters[Math.floor(m / 3)];
            mRec.period_name = this._getMonthName(month) + ' ' + year;
			mRec.period_display_name = mRec.period_name;
            mRec.period_start_date = mStart;
            mRec.period_end_date = mEnd;
            mRec.insert();
        }

        gs.info('Fiscal periods (Year, Quarter, Month) generated successfully.');
    },

    /* ===============================
     * Helpers
     * =============================== */

    _extractYear: function (str) {
        var m = str.match(/(20\d{2})/);
        return m ? parseInt(m[1], 10) : null;
    },

    _pad: function (n) {
        return (n < 10 ? '0' : '') + n;
    },

    _getMonthName: function (m) {
        return [
            'January', 'February', 'March', 'April', 'May', 'June',
            'July', 'August', 'September', 'October', 'November', 'December'
        ][m - 1];
    },


    type: 'IncentNowFiscalPeriodGenerator'
};
